import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import './Login.css';

const Login = () => {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({ email: '', password: '' });
  const [showPassword, setShowPassword] = useState(false);
  const [errors, setErrors] = useState({});
  const [globalError, setGlobalError] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [loginSuccess, setLoginSuccess] = useState(false);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
    if (errors[name]) setErrors(prev => ({ ...prev, [name]: '' }));
    if (globalError) setGlobalError('');
  };

  const validate = () => {
    const errs = {};
    if (!formData.email.trim()) {
      errs.email = 'Email is required';
    } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email)) {
      errs.email = 'Enter a valid email address';
    }
    if (!formData.password) {
      errs.password = 'Password is required';
    } else if (formData.password.length < 6) {
      errs.password = 'Password must be at least 6 characters';
    }
    return errs;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const validationErrors = validate();
    if (Object.keys(validationErrors).length > 0) {
      setErrors(validationErrors);
      return;
    }
    setIsLoading(true);
    setGlobalError('');
    try {
      // Replace with your actual auth API call
      await new Promise(resolve => setTimeout(resolve, 1500));
      setLoginSuccess(true);
      setTimeout(() => navigate('/'), 1200);
    } catch (err) {
      setGlobalError('Invalid email or password. Please try again.');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="login-page">

      {/* ── Decorative shapes (exact from original CSS) ── */}
      <div className="shape shape-top-big"></div>
      <div className="shape shape-top-small"></div>
      <div className="shape shape-right-circle"></div>
      <div className="shape shape-right-small"></div>
      <div className="shape shape-bottom-left"></div>

      {/* ── Navbar ── */}
      <nav className="navbar">
        <div className="logo-section" onClick={() => navigate('/home')}>
          <div className="logo-dot"></div>
          <span className="logo-text">Gene Guard</span>
        </div>
        <ul className="nav-links">
          <li><Link to="/learn-genetics">Learn Genetics</Link></li>
          <li><Link to="/genetic-disorders">Genetic Disorders</Link></li>
          <li><Link to="/counselling">Counselling</Link></li>
          <li><Link to="/genetic-assessment">Genetic Assessment AI</Link></li>
          <li className="active-link"><Link to="/dna" style={{color:'inherit'}}>DNA Testing</Link></li>
          <li><Link to="/about">About Us</Link></li>
        </ul>
      </nav>

      {/* ── Login Content ── */}
      <div className="login-container">
        <h2>Login</h2>
        <div className="underline"></div>

        <p className="welcome-text">Welcome back! Login to access the Gene Guard platform.</p>
        <p className="sub-text">
          Set your <span onClick={() => navigate('/signup')}>login page password</span>?
        </p>

        {/* Banners */}
        {loginSuccess && (
          <div className="success-banner" style={{ marginBottom: '20px' }}>
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" width="18" height="18">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"/>
            </svg>
            Login successful! Redirecting…
          </div>
        )}

        {globalError && (
          <div className="error-banner" style={{ marginBottom: '20px' }}>
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" width="16" height="16">
              <circle cx="12" cy="12" r="10"/>
              <line x1="12" y1="8" x2="12" y2="12"/>
              <line x1="12" y1="16" x2="12.01" y2="16"/>
            </svg>
            {globalError}
          </div>
        )}

        <form className="login-form" onSubmit={handleSubmit} noValidate>

          {/* Email */}
          <div className="input-group">
            <label htmlFor="email">Email</label>
            <input
              id="email"
              type="email"
              name="email"
              value={formData.email}
              onChange={handleChange}
              className={errors.email ? 'input-error' : ''}
              autoComplete="email"
            />
            {errors.email && (
              <div className="field-error">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" width="13" height="13">
                  <circle cx="12" cy="12" r="10"/>
                  <line x1="12" y1="8" x2="12" y2="12"/>
                  <line x1="12" y1="16" x2="12.01" y2="16"/>
                </svg>
                {errors.email}
              </div>
            )}
          </div>

          {/* Password */}
          <div className="input-group">
            <label htmlFor="password">Password</label>
            <input
              id="password"
              type={showPassword ? 'text' : 'password'}
              name="password"
              value={formData.password}
              onChange={handleChange}
              className={errors.password ? 'input-error' : ''}
              autoComplete="current-password"
            />
            {/* Eye toggle button */}
            <button
              type="button"
              className="pw-toggle"
              onClick={() => setShowPassword(prev => !prev)}
              aria-label={showPassword ? 'Hide password' : 'Show password'}
            >
              {showPassword ? (
                /* Eye-off icon */
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8"
                  strokeLinecap="round" strokeLinejoin="round">
                  <path d="M17.94 17.94A10.07 10.07 0 0 1 12 20c-7 0-11-8-11-8a18.45 18.45 0 0 1 5.06-5.94"/>
                  <path d="M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 8 11 8a18.5 18.5 0 0 1-2.16 3.19"/>
                  <path d="M14.12 14.12a3 3 0 1 1-4.24-4.24"/>
                  <line x1="1" y1="1" x2="23" y2="23"/>
                </svg>
              ) : (
                /* Eye icon */
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8"
                  strokeLinecap="round" strokeLinejoin="round">
                  <path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/>
                  <circle cx="12" cy="12" r="3"/>
                </svg>
              )}
            </button>
            {errors.password && (
              <div className="field-error">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" width="13" height="13">
                  <circle cx="12" cy="12" r="10"/>
                  <line x1="12" y1="8" x2="12" y2="12"/>
                  <line x1="12" y1="16" x2="12.01" y2="16"/>
                </svg>
                {errors.password}
              </div>
            )}
          </div>

          {/* Continue Button */}
          <button
            type="submit"
            className="continue-btn"
            disabled={isLoading || loginSuccess}
          >
            {isLoading ? (
              <>
                <span className="btn-spinner"></span>
                Loading…
              </>
            ) : loginSuccess ? (
              '✓  Logged In!'
            ) : (
              <>
                <span className="btn-icon">⊙</span>
                CONTINUE
              </>
            )}
          </button>

          {/* Divider */}
          <div className="divider">or continue with</div>

          {/* Social Buttons */}
          <div className="social-buttons">
            <button type="button" className="social-btn">
              {/* Google SVG */}
              <svg viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
                <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4"/>
                <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853"/>
                <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05"/>
                <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335"/>
              </svg>
              Continue with Google
            </button>

            <button type="button" className="social-btn">
              {/* GitHub SVG */}
              <svg viewBox="0 0 24 24" fill="#24292e" xmlns="http://www.w3.org/2000/svg">
                <path d="M12 0c-6.626 0-12 5.373-12 12 0 5.302 3.438 9.8 8.207 11.387.599.111.793-.261.793-.577v-2.234c-3.338.726-4.033-1.416-4.033-1.416-.546-1.387-1.333-1.756-1.333-1.756-1.089-.745.083-.729.083-.729 1.205.084 1.839 1.237 1.839 1.237 1.07 1.834 2.807 1.304 3.492.997.107-.775.418-1.305.762-1.604-2.665-.305-5.467-1.334-5.467-5.931 0-1.311.469-2.381 1.236-3.221-.124-.303-.535-1.524.117-3.176 0 0 1.008-.322 3.301 1.23.957-.266 1.983-.399 3.003-.404 1.02.005 2.047.138 3.006.404 2.291-1.552 3.297-1.23 3.297-1.23.653 1.653.242 2.874.118 3.176.77.84 1.235 1.911 1.235 3.221 0 4.609-2.807 5.624-5.479 5.921.43.372.823 1.102.823 2.222v3.293c0 .319.192.694.801.576 4.765-1.589 8.199-6.086 8.199-11.386 0-6.627-5.373-12-12-12z"/>
              </svg>
              Continue with GitHub
            </button>
          </div>

          {/* Bottom links */}
          <div className="bottom-links">
            <Link to="/signup">Create an account</Link>
            <a href="#forgot">Forgot password?</a>
          </div>
        </form>
      </div>
    </div>
  );
};

export default Login;
